1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two live cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with three neighbors (survival)", () => {
15	    // (1,0) has three live neighbors: (0,0), (2,0), (1,1) -> survives
16	    expect(nextGeneration([[0, 0], [2, 0], [1, 1], [1, 0]])).toContainEqual([1, 0]);
17	  });
18	  it.todo("should kill a live cell with four neighbors (overpopulation)");
19	  it.todo("should bring a dead cell with exactly three neighbors to life (reproduction)");
20	  it.todo("should oscillate a blinker, including negative coordinates");
21	  it.todo("should leave a block still life unchanged");
22	});
